Here are the public test cases for feature3_breadcrumb:
{
  "description": "A breadcrumb added before an error is captured is delivered to the breadcrumb pre-processing hook with its message intact; the subsequently captured error is reported as its own event.",
  "cases": [
    {
      "input": {
        "operations": [
          {
            "op": "add_breadcrumb",
            "message": "test"
          },
          {
            "op": "capture_exception",
            "message": "test"
          }
        ]
      },
      "expected_output": "captured_events=1\nevent[0].exception[0].type=RuntimeException\nevent[0].exception[0].value=test\nbreadcrumb[0].message=test\n"
    }
  ]
}

Here are the public test cases for feature4_4_global_scope_contexts:
{
  "description": "Structured context entries of different value kinds (string, boolean, number, and heterogeneous collection) set on the global scope are attached to a captured event, each normalized into an object that wraps the original value under a single value field.",
  "cases": [
    {
      "input": {
        "operations": [
          {
            "op": "configure_scope",
            "set_contexts": [
              {
                "key": "stringKey",
                "type": "string",
                "value": "stringValue"
              },
              {
                "key": "booleanKey",
                "type": "boolean",
                "value": true
              },
              {
                "key": "numberKey",
                "type": "number",
                "value": "123"
              },
              {
                "key": "collectionKey",
                "type": "collection",
                "value": [
                  "abc",
                  123,
                  true
                ]
              }
            ]
          },
          {
            "op": "capture_exception",
            "message": "test"
          }
        ]
      },
      "expected_output": "captured_events=1\nevent[0].exception[0].type=RuntimeException\nevent[0].exception[0].value=test\nevent[0].context.booleanKey={\"value\":true}\nevent[0].context.collectionKey={\"value\":[\"abc\",123,true]}\nevent[0].context.numberKey={\"value\":123}\nevent[0].context.stringKey={\"value\":\"stringValue\"}\n"
    }
  ]
}
